def test_valid_guess():
    # Valid guesses should have ok=True
    ok, guess_int, err = parse_guess("42")
    assert ok is True
    assert guess_int == 42
    assert err is None

def test_valid_guess_decimal():
    # Decimal input should be converted to int
    ok, guess_int, err = parse_guess("42.7")
    assert ok is True
    assert guess_int == 42
    assert err is None
